#include "interface.h"

#include <cstdint>
#include <string>
#include <vector>

namespace {

uint32_t encode_kmer(const std::string& s) {
  uint32_t code = 0u;
  for (char c : s) {
    uint32_t v = 0u;
    if (c == 'C') v = 1u;
    else if (c == 'G') v = 2u;
    else if (c == 'T') v = 3u;
    code = (code << 2) | v;
  }
  return code;
}

uint64_t checksum_counts(const std::vector<uint32_t>& counts) {
  uint64_t hash = 1469598103934665603ULL;
  for (uint32_t count : counts) {
    hash ^= static_cast<uint64_t>(count);
    hash *= 1099511628211ULL;
  }
  return hash;
}

}  // namespace

uint64_t kmer_histogram_checksum(const std::string& dna, int k, int iters) {
  const std::size_t bins = 1u << (2 * k);
  std::vector<uint32_t> dense(bins, 0u);
  for (std::size_t i = 0; i + static_cast<std::size_t>(k) <= dna.size(); ++i) {
    std::string kmer = dna.substr(i, static_cast<std::size_t>(k));
    dense[encode_kmer(kmer)] += 1u;
  }
  uint64_t hash = checksum_counts(dense);
  for (int iter = 1; iter < iters; ++iter) {
    hash ^= hash;
  }
  return hash;
}
